#include<bits/stdc++.h>
using namespace std;
int p[22000010];
char s[22000010];
int main()
{
    int tot=0;
    s[0]='~';
    s[++tot]='|';
    char ch=getchar();
    while(!isalpha(ch))
    {
        ch=getchar();
    }
    while(isalpha(ch))
    {
        s[++tot]=ch;
        s[++tot]='|';
        ch=getchar();
    }
    int ans=0,r=0,mid=0;
    for(int i=1;i<=tot;i++)
    {
        if(i<=r)
        {
            p[i]=min(p[mid*2-i],r-i+1);
        }
        while(s[i-p[i]]==s[i+p[i]])
        {
            p[i]++;
        }
        if(i+p[i]-1>=r)
        {
            r=i+p[i]-1;
            mid=i;
        }
        ans=max(ans,p[i]);
    }
    printf("%d",ans-1);
    return 0;
}
